prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?origId ?normId ?created WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    (?origId = "3c08e52742754da6a4065fc5787131dc") ||
    (?normId = "3c08e52742754da6a4065fc5787131dc")
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName 
       (COUNT(DISTINCT ?task) AS ?taskCount)
       (COUNT(DISTINCT ?start) AS ?startCount)
       (COUNT(DISTINCT ?end) AS ?endCount)
       (COUNT(DISTINCT ?catch) AS ?catchCount)
       (COUNT(DISTINCT ?xg) AS ?xorCount)
       (COUNT(DISTINCT ?pg) AS ?andCount)
       (COUNT(DISTINCT ?ebg) AS ?eventBasedCount)
       (COUNT(DISTINCT ?seq) AS ?seqFlowCount)
       (COUNT(DISTINCT ?mflow) AS ?messageFlowCount)
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?catch a bboExt:IntermediateCatchEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?xg a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?pg a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?ebg a bboExt:EventBasedGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?seq a bbo:SequenceFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?mflow a bboExt:MessageFlow ; tai:belongsTo ?choreo . }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?taskCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?task ?taskName ?participantNames ?loopType ?seqIn ?seqOut WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }

  OPTIONAL {
    ?task bboExt:initiatingParticipantRef ?partRef .
    ?participant a bboExt:Participant ; tai:belongsTo ?choreo ; bbo:name ?pName .
    FILTER(STRENDS(STR(?participant), ?partRef))
    BIND(?pName AS ?participantName)
  }

  OPTIONAL {
    { SELECT ?task (COUNT(DISTINCT ?in) AS ?seqIn) WHERE {
        ?in a bbo:SequenceFlow ;
            bbo:has_targetRef ?task ;
            tai:belongsTo ?choreo .
      } GROUP BY ?task
    }
  }
  OPTIONAL {
    { SELECT ?task (COUNT(DISTINCT ?out) AS ?seqOut) WHERE {
        ?out a bbo:SequenceFlow ;
             bbo:has_sourceRef ?task ;
             tai:belongsTo ?choreo .
      } GROUP BY ?task
    }
  }

  BIND(COALESCE(?taskName, "") AS ?taskName2)
  FILTER(?choreo = <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc>)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwType ?gwName ?gatewayDirection ?defaultSeq ?seqIn ?seqOut WHERE {
  BIND(<https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc> AS ?choreo)
  ?gw tai:belongsTo ?choreo ;
      a ?gwType .
  FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:EventBasedGateway, bboExt:ParallelGateway))
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?gatewayDirection . }
  OPTIONAL { ?gw bboExt:default ?defaultSeq . }

  OPTIONAL {
    { SELECT ?gw (COUNT(DISTINCT ?in) AS ?seqIn) WHERE {
        ?in a bbo:SequenceFlow ;
            bbo:has_targetRef ?gw ;
            tai:belongsTo ?choreo .
      } GROUP BY ?gw }
  }
  OPTIONAL {
    { SELECT ?gw (COUNT(DISTINCT ?out) AS ?seqOut) WHERE {
        ?out a bbo:SequenceFlow ;
             bbo:has_sourceRef ?gw ;
             tai:belongsTo ?choreo .
      } GROUP BY ?gw }
  }
}
ORDER BY ?gwType DESC(?seqOut) 
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?elemType ?elemName ?seqIn ?seqOut WHERE {
  BIND(<https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc> AS ?choreo)

  ?elem tai:belongsTo ?choreo ;
        a ?elemType .
  FILTER(?elemType IN (bboExt:ChoreographyTask, bboExt:StartEvent, bboExt:EndEvent, bboExt:IntermediateCatchEvent,
                         bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  OPTIONAL { ?elem bbo:name ?elemName . }

  OPTIONAL {
    { SELECT ?elem (COUNT(DISTINCT ?in) AS ?seqIn) WHERE {
        ?in a bbo:SequenceFlow ;
            bbo:has_targetRef ?elem ;
            tai:belongsTo ?choreo .
      } GROUP BY ?elem }
  }
  OPTIONAL {
    { SELECT ?elem (COUNT(DISTINCT ?out) AS ?seqOut) WHERE {
        ?out a bbo:SequenceFlow ;
             bbo:has_sourceRef ?elem ;
             tai:belongsTo ?choreo .
      } GROUP BY ?elem }
  }

  FILTER( (COALESCE(?seqIn,0) = 0) || (COALESCE(?seqOut,0) = 0) )
}
ORDER BY ?elemType ?elemName
LIMIT 25
